-- Chef Theo - migration 22 : categories d'emplacements d'images pour la
-- filiere Cuisine (Recettes, Legumes et ingredients, Fruits), organisees en
-- sous-groupes. Meme fonctionnement que les emplacements de materiel
-- existants : nom + emplacement d'image neutre tant qu'aucune image n'est
-- fournie. Rien touche parmi les emplacements deja existants.
-- A coller dans Supabase Dashboard > SQL Editor > New query, puis "Run".

alter table public.materiel_items add column categorie text;
alter table public.materiel_items add column sous_groupe text;

on conflict (filiere_id, name) do nothing;
